import{_ as r,g as t,h as i,U as l}from"./chunks/vitepress-theme-teek.BIbhbr3v.js";const d=JSON.parse('{"title":"向内思变：当疫情给世界按下暂停键，去重构生活秩序","description":"摘要总结：当世界按下暂停键，如何避免内耗？本文记录了笔者三年间的“自我重构”实验。文章摒弃了单纯的情绪宣泄，而是利用分解法、渐进明细和统计分析等工程思维，对健康饮食、知识体系、时间分配及远程协作进行了系统化改造。这是一份关于如何在无常的外部环境中，建立内在确定性秩序的行动指南。","frontmatter":{"date":"2023-01-08T10:23:50.000Z","title":"向内思变：当疫情给世界按下暂停键，去重构生活秩序","description":"摘要总结：当世界按下暂停键，如何避免内耗？本文记录了笔者三年间的“自我重构”实验。文章摒弃了单纯的情绪宣泄，而是利用分解法、渐进明细和统计分析等工程思维，对健康饮食、知识体系、时间分配及远程协作进行了系统化改造。这是一份关于如何在无常的外部环境中，建立内在确定性秩序的行动指南。","permalink":"/about/growth/inner-experience","coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/refactor_life.png","sticky":1,"top":true,"categories":"个人成长","tags":["健康","时间","悦读时光","远程协作","疫情"]},"headers":[],"relativePath":"about/growth/inner-experience.md","filePath":"40.关于/30.成长随笔/10.向内思变：当疫情给世界按下暂停键，去重构生活秩序.md"}'),o={name:"about/growth/inner-experience.md"};function s(n,a,e,p,g,h){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="向内思变-当疫情给世界按下暂停键-去重构生活秩序" tabindex="-1">向内思变：当疫情给世界按下暂停键，去重构生活秩序 <a class="header-anchor" href="#向内思变-当疫情给世界按下暂停键-去重构生活秩序" aria-label="Permalink to “向内思变：当疫情给世界按下暂停键，去重构生活秩序”">​</a></h1><blockquote><p><strong>摘要总结</strong>：当世界按下暂停键，如何避免内耗？本文记录了笔者三年间的“自我重构”实验。文章摒弃了单纯的情绪宣泄，而是<strong>利用分解法、渐进明细和统计分析等工程思维，对健康饮食、知识体系、时间分配及远程协作进行了系统化改造。</strong>这是一份关于如何在无常的外部环境中，建立内在确定性秩序的行动指南。</p></blockquote><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/refactor_life.png" alt="目标到践行思维流程示意图" style="width:100%;border-radius:8px;"><h2 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to “写在前面”">​</a></h2><p>自去年 7 月份迁移几篇旧文后，笔者就没有继续写软文了，想不到再次写文章时疫情政策已经调整，且初步实现了开放。那么问题来了，为什么要继续写文章呢？概括来讲，有两个方面的原因：</p><ul><li><strong>直接原因：</strong>疫情这三年，每个人都体验到了不同于之前的 “难”，也都有属于自己独一份的经历。笔者这三年也在疫情影响的基础上，经历了一些之前未曾遇到过的事情，幸运的是从中也学到了一些东西，并在生活实践中去尝试、去改变。因此，在疫情进入初步放开的新阶段，也想做一次复盘总结。</li><li><strong>间接原因：</strong>复盘总结的可选方式有很多种，但写文章是笔者觉得挺适合自己的一种方式。所以，笔者决定借助开放平台来继续完成一篇复盘总结文章。既锻炼下自己的写作能力，也能借助开放平台或多或少收到一些反馈与建议。鉴于笔者没有过多思考要总结哪些东西，所以标题也命名为 “漫谈疫情这三年向内思变”。</li></ul><p>疫情期间，笔者基本没有怎么出过远门，甚至阴差阳错地给自己安排了更多的独处时间。周末也倒逼自己按照比较严格的作息推动业余实践，尝试向内探索。因此，所谓 “向内思变”，用时髦的说法也叫 “闭关”，接下来就阐述下要漫谈的话题。</p><h2 id="漫谈话题" tabindex="-1">漫谈话题 <a class="header-anchor" href="#漫谈话题" aria-label="Permalink to “漫谈话题”">​</a></h2><p><strong>健康</strong>，拥有的时候经常不会被珍惜，失去的时候却追悔莫及，但重新找回后却很容易再次不被珍惜（不难理解，这就是人性）</p><p><strong>读书与学习</strong>，一个被广为熟知的话题，但笔者在这方面是有一定自信的，因为有过比较正向的实践，多少有点底气。自大学时代开始，笔者在这方面有一定的嗜好，且系统践行了此嗜好，还通过啃一些跨专业的书来学习，直至可以抛弃原来的专业，在毕业时也留下了两篇关于这方面的总结文章。当然，任何时候、任何人的经历都代表不了实力。本次漫谈笔者会结合自己的经验、思考与总结来梳理，尽最大努力让这个话题起到抛砖引玉的作用，有兴趣的小伙伴在以后的日子里可共同进步。</p><p><strong>时间管理</strong>，这个话题虽被大家熟知，却很少有人能自信地说 “自己能很好地管理时间”，笔者肯定也不例外。但本次漫谈会梳理下笔者自己在实操方面的尝试，思考与总结。</p><p><strong>混合工作制</strong>，这个话题在疫情到来后被大家熟知，所以笔者这里也未必能分享出多么稀奇古怪的见解，但同样会结合实操给出自己的思考与总结。</p><h2 id="漫谈健康" tabindex="-1">漫谈健康 <a class="header-anchor" href="#漫谈健康" aria-label="Permalink to “漫谈健康”">​</a></h2><h3 id="健康危机" tabindex="-1">健康危机 <a class="header-anchor" href="#健康危机" aria-label="Permalink to “健康危机”">​</a></h3><p>鉴于笔者在大学阶段自由学习与探索的勇气可嘉，因此在经历两次 “校园互联网小作坊” 的锻炼后，毕业时选择的工作自然而然地成为了大学兴趣的延续。当然，也延续了很多大学阶段养成的对健康不利的习惯，作息无规律，仗着无知挥霍身体；无健康意识，不怎么锻炼身体，比如：</p><ul><li>很少吃早饭，经常吃早中饭或者午饭。除了工作、学习和娱乐勤快点，别的方面比较懒。</li><li>长期熬夜，业余也喜欢学点东西，写点代码（大概率是走出校园后看到了人外有人，随着工作的深入，慢慢意识自身不足，想要提升一些技能）。</li></ul><p><strong>人无作息规律地熬一天不累，熬十天就累了，熬几年也就要坏事了</strong>。就这样经过长年累月地洗礼，健康也在疫情到来的第一年亮起了小红灯。当然，经过医生、家人等多方的协力帮助，以及自己的坚忍硬扛，最终康复了。期间虽然经历了比疫情放开后大部人转阳痛苦且印象深刻多倍的事情，但不是本文的重点，这里只留下笔者事后深刻反思的几个心得：</p><ul><li>不好的事情如果已经到来，懊悔等悲观情绪都没有任何用处，只能是想尽一切办法 <strong>“先治病救命，休养康复，然后再谈健康养生”。</strong></li><li>现代医疗虽能救死扶伤，但终究只是最后的止损方式。我们<strong>只有在日常注重预防保健、培养健康意识，注重养身修身，才有可能在这个社会上走的更远</strong>。</li><li>随着社会的发展，<strong>人被技术圈和社会圈包裹了起来，人与自然之间的距离也就越来越远了，自然人也就发生了异化</strong>（放眼望去，身边充满着太多类似笔者这种不够注重自身健康的人）。</li></ul><h3 id="健康知识学习" tabindex="-1">健康知识学习 <a class="header-anchor" href="#健康知识学习" aria-label="Permalink to “健康知识学习”">​</a></h3><p>既然已经知晓自身问题且暂时止损了，自然要继续寻找更长远的解决方法。但方法不会凭空从天上掉下来的，它需要自己去寻找。笔者寻找方法的主要途径是：<strong>向专业或有经验的人咨询，向书本上的健康标准和知识找</strong>。</p><h4 id="_1、向有专业或有经验的人咨询" tabindex="-1">1、向有专业或有经验的人咨询 <a class="header-anchor" href="#_1、向有专业或有经验的人咨询" aria-label="Permalink to “1、向有专业或有经验的人咨询”">​</a></h4><p>由于笔者仍然保持着大学时代学会的“免费”思维，所以在接近康复出院的时候就开始跟医生、医护、病友等以聊天的方式咨询。众所周知，医生是经常传授病人一些健康知识的专业人员，医护是长年累月协助病人康复训练的专业人员，病友是那些与自身有着相同失误的人，向这几波人咨询更能习得比较正向的建议或小技巧。这一阶段积累了一些碎片化的健康意识，康复训练小技巧，以及戒掉不良生活习惯的注意点，也<strong>为后面的防治宜早、起居有常、适量运动等原则做了铺垫</strong>。</p><h4 id="_2、学习健康标准和知识" tabindex="-1">2、学习健康标准和知识 <a class="header-anchor" href="#_2、学习健康标准和知识" aria-label="Permalink to “2、学习健康标准和知识”">​</a></h4><p>健康其实是有标准、有依据的：</p><p>*《皇帝内经》中的标准：形与神俱，而终其天年，度百岁乃去。 *现代的健康标准：<strong>生理健康、心理健康、社会及自然环境适应良好，道德良好，并达到人之天年</strong>。</p><p>如上所述，健康标准简单且易懂，但它不足以指导大部人去实践（除非是不世出的罕见人才，看到标准后就能推导出符合实际的解法）。所以笔者结合自身经历和健康知识，<strong>进一步采用 “分解” 和渐进明细的方式，学着梳理出一些健康原则</strong>：</p><ul><li><strong>合理饮食</strong>，日常饮食注重杂食多样，确保能量、营养、性味平衡。</li><li><strong>起居有常</strong>，尝试改变生活方式，健康有序，防戒不良生活习惯。</li><li><strong>适量运动</strong>，因人因时因地地制定出一套健身运动的项目，循序渐进、持之以恒地坚持下去，保持健康一点的形体，提高对环境的适应能力</li><li><strong>静养心神：</strong><ul><li>给自己的生活做减法，宁可不合群，也要避免接触一些没有用还容易内耗的人和事。</li><li>多读点书，尝试将书中的一些知识用到工作和生活中。</li></ul></li><li><strong>防治宜早</strong>，吸取医生的建议，对亚健康状态及疾病坚持预防为主、早防早治</li></ul><p>最后，为保证自己在理论意识上更注重身体健康，笔者还拜读了毛教员在青年时期写下的《体育之研究》。读过教员鞭辟入里的文章后，也更从理论上明白了：<strong>“体者，载知识之车而寓道德之舍也。体育一道，配德育与智育，而德智皆寄于体。”</strong></p><h4 id="_3、健康实践" tabindex="-1">3、健康实践 <a class="header-anchor" href="#_3、健康实践" aria-label="Permalink to “3、健康实践”">​</a></h4><p>结合沉淀下来的原则，笔者花费了 1.5 年的时间，进行了两个方面的实践：</p><ul><li>工作日早上坚持做早饭，三餐慢慢靠向合理均衡。周末培养一些做饭的技能，借助烟火气来平衡下工作与生活。</li><li>设定减肥目标，通过控制饮食、增强体育锻炼活动来实现体重的减少，提升自身健康。</li></ul><p>随着时间的流逝，笔者现在也能自己做出 75 分的家常菜了（特别感谢很多师傅指导），且将下面这张图作为自己的日常饮食原则：</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic1.png" alt="日常饮食原则示意图" style="width:100%;border-radius:8px;margin-bottom:20px;"><p>关于健身减肥方面的实践，笔者这里只阐述下主要实践思路，实践细节可参考笔者之前写的一篇文章：<a href="/about/growth/weight-loss">减肥这件小事阶段随笔汇总</a>。</p><p>关键点 1：<strong>要考虑打工人工作比较忙碌的客观现实，将时间周期拉的长一点，目标拆解的细一点，可分阶段来</strong>。我们可以结合身边的很多例子来反思下，<strong>为什么那么多人喊着健身和减肥，真正成功的却不多呢？</strong>是耐力不够，还是客观环境不允许呢？笔者觉得两个原因都有，如果时间足够充裕，用这么多空闲时间来专注地完成一件正确的事情是没有大问题的。可现实生活中时间不会多么充裕，正是基于客观考虑，笔者才调整了实践思路：</p><ul><li><strong>严格阶段：</strong>基于<strong>“管住嘴，迈开腿”</strong>的准则，每月减 5 斤，半年减 30 斤（已完成实现）</li><li><strong>巩固阶段：</strong>在 “管住嘴” 的基础上， <strong>侧重 “迈开腿”</strong>的准则，<strong>加大运动量，提升自身身体素质</strong>（2022年执行良好）</li><li><strong>持续阶段：</strong>将<strong>“每天锻炼一小时，快乐工作五十年”</strong>作为一个长期习惯来贯彻下去（希望 2023 年及以后的日子里可以继续做到）</li></ul><p>关键点 2：实践过程中<strong>借助体脂秤的指标和数据统计，来定期分析自身数据，及时发现、纠正实操过程中的问题（这是笔者所在行业的惯用套路）</strong>。我们可以继续结合生活中的例子来看下，自己可有花些时间来反思、复盘自身存在的问题，然后调整行动呢？大部分应该都没有这么做。其实，笔者之前在这方面做的也特别少，后来随着工作和生活阅历的增加，慢慢注重这方面了。</p><h4 id="_4、健康小结" tabindex="-1">4、健康小结 <a class="header-anchor" href="#_4、健康小结" aria-label="Permalink to “4、健康小结”">​</a></h4><p>健康这个话题聊的差不多了，笔者在这个话题的最后简单分享两个自己学到的、且感觉比较实用、可广泛应用的迭代实践套路。有兴趣的朋友可去深入学习，如果还能在工作和生活中尝试起来，相信会取得更好的效果。</p><p>(1) 目标 -&gt; 问题 -&gt; 诊断 -&gt; 方案 -&gt; 践行 （套路来自《原则》这本书，该书在疫情前被笔者知晓后阅读，疫情后又翻了下，跟老朋友们也强烈推荐过）</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic2.png" alt="目标到践行思维流程示意图" style="width:100%;border-radius:8px;margin-bottom:20px;"><p>2、一个全面质量管理的思想基础和方法依据，循环式品质管理 PDCA，又称戴明环。由戴明提出，据说他十分热爱统计学，二战时曾将统计学应用于制造业，后来在日本传授质量控制，随着日本制造技术的逐渐发达，戴明也成为了比较著名的人物。</p><h2 id="漫谈读书与学习" tabindex="-1">漫谈读书与学习 <a class="header-anchor" href="#漫谈读书与学习" aria-label="Permalink to “漫谈读书与学习”">​</a></h2><h3 id="_1、读书的目的" tabindex="-1">1、读书的目的 <a class="header-anchor" href="#_1、读书的目的" aria-label="Permalink to “1、读书的目的”">​</a></h3><blockquote><p>读书与学习的区别是什么呢？</p></blockquote><p>在笔者看来，<strong>读书与学习是两码事，读书不等于学习，想要学习成长倒是可以多读点书。</strong>当然，有些人会把读书当成一种习惯和爱好，但笔者想继续问的是：习惯和爱好不是凭空来的，这种习惯和爱好背后的本质原因和动力又是什么呢？可能答案中多少会涵盖点 “想从读书中学到点东西”吧。</p><p>身处一个知识迭代速度和生活节奏都在加快的时代，“焦虑”与“迷茫”会时不时来敲门。因此，<strong>为应对社会生活中的焦虑与迷茫，人们选择了各种各样的方式，读书与学习自然也成为了一种常用的方式</strong>。笔者之前主动跟人交流的动力不大，所以读书与自我规划学习也是笔者的选择。</p><p>因此，如果有人问起 “你读书的目的是什么”，笔者会结合读过的《纳瓦尔宝典》这本书给出现在的答案：<strong>构建自己的心智模型</strong>。当然，如果在未来 N 年后有人再问起这个问题，笔者希望自己可以结合《穷查理宝典》这本书和查理芒格这个人给出比当前更深入和细化的答案（目前不能给这个答案，因为笔者自己构建的心智模型还不够好）。</p><h3 id="_2、读书的方式" tabindex="-1">2、读书的方式 <a class="header-anchor" href="#_2、读书的方式" aria-label="Permalink to “2、读书的方式”">​</a></h3><p>随着时间的推移，笔者在读书方面体验了以下三种方式：</p><ul><li>自由式阅读，作为一种娱乐和爱好，比如阅读一些小说或自己觉得有趣的书。</li><li>填鸭式阅读，为短时间学习、了解某个技能或东西，而选择的类似应试教育的方式。</li><li>海绵式阅读，结合自身遇到的问题通过阅读学习来找答案，或阅读学习的过程基于书中的阐述来结合实际提炼出可指导实践的“套路”。</li></ul><p>我们并不需要像辩论赛那样争论、PK 出上述哪种方式好，哪种方式不好。因为每种方式都有可能、或多或少助力我们成长。从实践效果来看，或许海绵式阅读是大多数人认可的方式，但有些采用自由式阅读的人真的在某些方面比采用海绵式阅读的人优秀；从时间维度来看，没有自由式、填鸭式的阅读，也很难直接转变为海绵式阅读。</p><p>在笔者看来，我们要关注的不是单选题，是<strong>“全都要”，要学会在不同的场景下切换到不同的阅读方式。即使是同一个人，也可根据不同的场景、不同的时间来切换到不同的阅读方式</strong>。所以，这里再做一个大胆又狂妄地的论断：<strong>为什么很多人读了很多的书，却依旧过不好这一生？因为纵使一个人满腹经纶，但 TA 没有清晰的认清问题本质，做不到学以致用与知行合一（书生误国也是这个道理）</strong>。</p><h3 id="_3、读书工具选择与实践" tabindex="-1">3、读书工具选择与实践 <a class="header-anchor" href="#_3、读书工具选择与实践" aria-label="Permalink to “3、读书工具选择与实践”">​</a></h3><blockquote><p>大学时代，自接触互联网后，笔者依旧会买一些纸质书来看，但也坚信“信息化”是大势所趋，一个大学生在学好数学等基础学科的基础上，应该花些精力来学习了解下计算机技术。经历疫情这三年后，笔者再次坚信 “数字化” 是继 “全球化” 之后的大势所趋。</p></blockquote><p>在阅读工具的选择方面笔者经历了以下几个阶段：</p><ul><li>纸质书 =&gt; 互联网信息</li><li>纸质书 + 互联网信息 + Kindle 电子书</li><li>纸质书 + 互联网信息 + 国内阅读APP（微信阅读、蜗牛读书等）</li></ul><p>目前，“纸质书 + 微信阅读 + 互联网信息”成为了笔者最终选择的组合工具。在 2021 年底，笔者认为微信读书推出的年度报告产品已不足以总结自己在阅读方面的全貌，而且在闲暇的时候觉得自己在阅读方面不够系统化。因此，就创建了一个<strong>“阅读准则表格”，用于指导自己的阅读实践</strong>。表格<strong>依旧采用了分解与渐进明细的思路</strong>：</p><ul><li>明确自己当前的定位，划分出四个“定位圆圈”，对每个圆圈进一步分解，从而划分出几个分类： <ul><li><strong>工作技能圈</strong>，包括编程技术学习、职业发展学习、互联网行业与科技 三类</li><li><strong>生活短板补充圈</strong>，目前只包括身体健康与居家这一个大类</li><li><strong>个人能力补充圈</strong>，包括统计与数学、经济与财经知识学习 两类</li><li><strong>人文哲思调剂圈</strong>，包括哲思人生、历史读物、文学与小说 三类</li></ul></li><li>为每一个分类配备对应的阅读工具与实践原则</li></ul><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic3.png" alt="目标到践行思维流程示意图" style="width:100%;border-radius:8px;margin-bottom:20px;"><h3 id="_4、小结" tabindex="-1">4、小结 <a class="header-anchor" href="#_4、小结" aria-label="Permalink to “4、小结”">​</a></h3><p>在上述“阅读准则表格”的协助下，阅读与学习这件小事在疫情期间也变得比之前明晰起来，且由于 2022 年频繁居家，节省下来的时间也就多了，笔者希望能继续向着“构建自己的心智模型”这个方向实践下去。</p><p>阅读与学习这个话题到此也基本漫谈完了，对这个话题或阅读工具感兴趣的朋友可以看下凯文凯利在几年前写的《必然》这本书（笔者坚信，微信读书这个产品在发展的过程中，其团队中肯定有人读过这本书）。当然，如果不觉得笔者在做广告，也可看下笔者毕业前留下的两篇相关文章：</p><ul><li><a href="https://zhuanlan.zhihu.com/p/386490626" target="_blank" rel="noreferrer">读《必然》后敲字有聊</a></li><li><a href="https://zhuanlan.zhihu.com/p/386483268" target="_blank" rel="noreferrer">读《智能时代》和《大学之路》后随笔</a></li></ul><h2 id="漫谈时间管理" tabindex="-1">漫谈时间管理 <a class="header-anchor" href="#漫谈时间管理" aria-label="Permalink to “漫谈时间管理”">​</a></h2><h3 id="_1、时间不够用问题" tabindex="-1">1、时间不够用问题 <a class="header-anchor" href="#_1、时间不够用问题" aria-label="Permalink to “1、时间不够用问题”">​</a></h3><blockquote><p>时间是我们在这个世界上最优质和公平的资产，可它也能是让人在其面前最无奈。因此，如何利用、管理自己的时间也成为了每个人的必修课。</p></blockquote><p>身处时间碎片化、角色多元化的社会，我们的时间变得越来越碎，每个角色背后也都有一堆琐碎的事不断涌进来。很多人觉得时间管理、时间不够用是老生长谈的话题，身边充斥着讲这个方面的人和书，但没有多少实际的用处。笔者曾试图分析过这个现象，最终总结出来的主要原因有 3 个：</p><ul><li>即便读遍全天下关于时间的书，遍访了全天下有相关经验的人。只要不去行动，就是白费功夫，与其这般努力，不如躺平。</li><li>每个人遇到的问题和设定的目标不同，采用的处理方式自然也不同，有些人的总结未必适合自己，拿来借鉴也未必能起到多少效果。</li><li>调整后的效果需要时间来证明，在没有看到效果前大多数人都容易放弃。即使看到了短期的效果，只要解决了当前棘手的问题，很少有人会选择继续保持。</li></ul><p>刚好在疫情这三年，笔者有机会基于遇到的问题，在这方面尝试改善了下。重新拥有健康的身体后，有几个难题摆在了笔者面前：</p><ul><li>随着工作年限和阅历的增加，需要依赖发现、分析后才能清晰的问题和事务相较之前占比多了，压力也随之上升，时间变得明显不够用。</li><li>合理的饮食、健康的身体、比较有规律的作息被列为头等大事，有些实践需要时间落地，有些改变需要依赖时间才能有效果</li><li>重新拥有健康的身体后，笔者不但想在工作方面多做些正确的事，还想在为数不多的业余时间推动“读书与学习”这件小事，通过构建稳健的心智模型来应对不稳定的大环境。</li></ul><p>笔者相信，有过类似经历的人肯定能更明白其中的矛盾与酸楚，面对很多件抢占时间资源的事务，又不得不逼着自己想方设法找到解决办法，真的蛮有压力的。当然，躺平和摆烂是一种方式，可人躺久了也会不自觉地想要尝试突破一下局限，与其让问题与环境倒逼自己改变，不如自己思变。</p><h3 id="_2、分阶段调整时间管理" tabindex="-1">2、分阶段调整时间管理 <a class="header-anchor" href="#_2、分阶段调整时间管理" aria-label="Permalink to “2、分阶段调整时间管理”">​</a></h3><h4 id="第一阶段-疯狂做减法-专注重要的事" tabindex="-1">第一阶段：疯狂做减法，专注重要的事 <a class="header-anchor" href="#第一阶段-疯狂做减法-专注重要的事" aria-label="Permalink to “第一阶段：疯狂做减法，专注重要的事”">​</a></h4><blockquote><p>不推荐的严格时间表，形如 7:20-7:50 起床、洗漱；7:50-8:30 锻炼身体；8:20-8:50: 吃早饭...... 这样简单地把一天时间分为线段的作息日程表.</p></blockquote><p><strong>（1）丢弃不靠谱的严格时间表，为自己减压</strong></p><ul><li>普通人勤奋些是对的，但逼着自己执行“严格时间表”只会让自己变得更加焦虑。</li><li>越是努力地执行严格的时间表，就越体会到挫败感、焦虑感，我们不该用理想化的方法要求自己。</li></ul><p><strong>（2）重新理解与应用“时间四象限”</strong></p><ul><li>使用清单 List 来管理事务。基于事务的重要程度，刻意忽略不重要的事，即紧急不重要和不紧急不重要的事务（干掉紧急不重要的事务有点过于暴力，也容易被别人误解。但由于笔者在第一阶段还处于救火阶段，会比较狠）</li><li>错开大众上班高峰时间，上午给自己预留 2.5 小时的无干扰时间。半小时用于健身，1.5 小时用于处理重要不紧急的事</li><li>正常工作时间处理重要且紧急的事，尽最大努力将重要且紧急的事务快速干掉，并尽最大努力避免重要不紧急的事务演变为重要且紧急的事务</li></ul><p><strong>（3）重新调整周末时间</strong></p><ul><li>周六无重要事不约不逛：周六上午预留网上冲浪和阅读文章充电时间，周六下午预留健身时间</li><li>周日上午随意，下午与晚上预留出阅读与学习时间</li></ul><p><strong>在这种“快刀斩乱麻”式的操作下，近小半年后笔者发现自己在工作方面不那么像四处灭火的“捉急状态”了</strong>。健康、读书与学习两方面的习惯得以保住，虽然体重变化存在小范围波动，但健身减肥的胜利果实也被巩固住了。</p><h4 id="第二阶段-升级清单管理" tabindex="-1">第二阶段：升级清单管理 <a class="header-anchor" href="#第二阶段-升级清单管理" aria-label="Permalink to “第二阶段：升级清单管理”">​</a></h4><p>在这个阶段，鉴于笔者看了一些时间管理相关的书，比如《哈佛时间管理课》、《哪里没有时间》等书。结合自己在第一阶段的问题，决定在第二阶段对清单进行改善。清单是个好东西，能用来梳理、分析自己的时间利用是否符合预期，有助于使用者不断思考如何将日常任务做的更好。<strong>列出来清单后能降低甚至避免焦虑，因为在执行时不是从大脑中提取，而是从清单中读取</strong>。</p><p>在升级清单管理前，笔者只有一个主要用来管理工作相关事务的清单，业余时间是没有清单管理的。但随着健康与业余自我充电相关的投入加大，升级清单管理有了一定的必要条件。<strong>升级清单管理的主要思路依旧运用了分解与渐进明细，将清单分为：碎片清单、工作日-日常清单、周末-日常清单三类</strong>：</p><ul><li><p><strong>碎片清单：</strong></p></li><li><p>作为大脑的缓冲池而存在，收集大脑基于客观因素或主观思绪而产生的事务（不区分优先级，不区分事务大小）。把事务丢进碎片清单的目的是要在其他合适的时间再去思考它、处理它，同时保持当下时间的专注。</p></li><li><p><strong>碎片清单是另外两个清单的主要输入，建立碎片清单，需要养成每天把碎片及时装进日常清单的习惯</strong></p></li><li><p>删除长时间没有被迁移且渐进明细到日常清单的事务</p></li><li><p><strong>日常清单(工作日)：</strong></p></li><li><p>用于收集工作日的日常事务，其输入主要来自碎片清单或临时加进来的重要且紧急事务。</p></li><li><p>日常清单收集事务不能照搬碎片清单，而是碎片清单的再次分解与渐进明细。进入日常清单的任务必须有子任务或关键步骤，且基于再次分解的结论标出预估耗时。</p></li><li><p><strong>日常清单(周末)：</strong></p></li><li><p>用于收集周末的日常事务，其输入主要来自碎片清单，优先对健康、读书与学习相关的事务；次优先排日常起居、购物等事务。</p></li><li><p>日常清单收集事务依旧不能照搬碎片清单，而是再次分解和渐进明细碎片清单。进入周末日常清单的任务必须包含子任务和关键步骤，且基于再次分解的结论标出预估耗时。</p></li></ul><p>就这样，升级后的三个清单进一步优化了笔者的时间。持续几个月后，笔者也<strong>慢慢变得敢于决断，哪怕决断错了也要干。因为改变说起来容易做起来难，如果在做的过程中还惧怕错了，那只能是被束缚得各种不适，改变也就很可能夭折。</strong></p><h4 id="第三阶段-刻意统计并调整时间" tabindex="-1">第三阶段：刻意统计并调整时间 <a class="header-anchor" href="#第三阶段-刻意统计并调整时间" aria-label="Permalink to “第三阶段：刻意统计并调整时间”">​</a></h4><p>经历了前两个阶段的改变，某天，笔者在娱乐的时候刚好看到有个 UP 主在讲 “进入人工智能时代后，人要怎么做才能既不失业，还能活的不错”。鉴于笔者统计分析的意识已经建立起来（统计学与数学知识应用依旧存在短板），所以笔者冒出了一个想法：<strong>UP 主列出的这个东西可能就是当下自己没有梳理过的时间分配准则。</strong></p><p>废话不多说，这里直接贴出 UP 主给出的时间消耗建议，也是笔者在第三阶段的时间统计与调整准则，具体如下图：</p><div style="display:flex;justify-content:space-between;align-items:flex-start;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic4.png" alt="当前时间消耗现状" style="width:49%;border-radius:8px;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic5.png" alt="时间调整建议" style="width:49%;border-radius:8px;"></div><p>因此，笔者结合准则和自己在第一、二阶段沉淀下来的时间分配情况，整出了一个粗糙的时间统计。整个时间统计采用了由局部到整体的方式：</p><p>优先统计工作日早上至午休这段时间的分配，基于统计情况调整时间；然后统计并调整午休、下午和晚上等时间的分配 以此类推，次优统计并调整周末时间的分配（为避免自己变成有强迫症的人，周末调整没有工作日拆解的细，为自己预留一些挥霍的自由） 笔者这里给出统计与调整示意如下：</p><div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:20px;border-radius:8px;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic6.png" alt="工作日早上至上班前时间统计与调整" style="width:49%;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic7.png" alt="午休时间统计与调整" style="width:49%;"></div><p>至此，刻意统计与调整阶段的阶段也漫谈完了。笔者在这一阶段还挺觉得有成就感的，因为终于有机会在工作之外初级又粗糙地运用了统计学分析，很好地鼓励自己在统计学分析方面继续加大投入力度。</p><h2 id="漫谈混合工作制" tabindex="-1">漫谈混合工作制 <a class="header-anchor" href="#漫谈混合工作制" aria-label="Permalink to “漫谈混合工作制”">​</a></h2><p>书接上文，<strong>如果说时间管理其实就是对时间这一个维度进行切割，然后把工作与生活中的事务填充进去，那么混合工作制就是基于物理空间和时间这两个维度来切割平面，然后把工作与生活中的事务填充进去</strong>。因此，笔者要漫谈的最后一个话题就是混合工作制。</p><p>这里所谓的“混合工作制”，对打工人来讲其实就是一部分时间在办公室工作，一部分时间居家远程办公。如果没有疫情，这种方式在国内还不会被大范围运用，虽然互联网行业一直有弹性工作制，但国内很少有企业让员工能持续几天甚至一个月居家办公。笔者认为，疫情只是更显象化了这种方式，因为在疫情出现之前，国外真的有公司在实践，而且国外的自由职业者是比国内多出很多的。</p><p>这里不是要展开争论，而是想抛出问题：<strong>我们虽然在疫情期间熟悉了这种工作模式，但我们可觉得自己能很好地处理这种模式呢？疫情总会过去的，在疫情后我们要不要继续实践混合工作制呢？</strong></p><h3 id="_1、适应混合工作制" tabindex="-1">1、适应混合工作制 <a class="header-anchor" href="#_1、适应混合工作制" aria-label="Permalink to “1、适应混合工作制”">​</a></h3><p>如上所述，混合工作制是基于空间与时间两个维度来安排要处理的事务，所以适应混合工作制，就是基于二维平面来安排好自己的工作与生活，试着把日子过得顺畅。</p><p>笔者不敢说自己在疫情期间很好地适应了混合工作制，因为在疫情早期居家办公真的很累，工作与生活没有了界限，有时觉得自己除了睡觉就一直在工作，回到公司上班的时候就觉得特别爽。但随着疫情的多次反复，也就有了一次次地尝试改变自己来适应居家办公，拥抱混合工作制。在这种客观条件的倒逼下，终究还是适应了，也实现了向内思变。</p><p>混合工作制最大的痛点是解决居家办公的苦恼，善用居家办公的优势，甚至把居家办公的经验适当地用在办公室工作中，从而实现真正的混合工作。在居家办公的时候，笔者觉得有以下几个要点需要注意：</p><ul><li>居家办公时要强调效果和效率。效果源于对重要业务或任务的识别，效率源于专注地运用工具做正确的事</li><li>划定出专门的办公空间，有效区分起居空间与办公区间</li><li>基于对重要业务和任务的识别，使用比较清晰的清单和日程表来协助重要事务的推动。笔者这里依旧沿用了时间管理中提到的三个清单：碎片清单、日常任务清单（工作日）、日常任务清单（周末）。</li><li>善用远程办公工具，电话会议室一种重要的沟通协作方式，开好电话会议能更明确重点，提升效率。</li></ul><p>当从居家办公切换到办公室工作环境中，除了不用划定专门的办公空间，很多经验都是可以继续沿用的。只有在碰到特别重要紧急的事情或者娱乐的事情才需要与同事当面沟通交流，这在一定程度上可以提升个人工作效率，去尝试摆脱“无头苍蝇式的忙碌”。</p><h3 id="_2、延伸思考混合工作制" tabindex="-1">2、延伸思考混合工作制 <a class="header-anchor" href="#_2、延伸思考混合工作制" aria-label="Permalink to “2、延伸思考混合工作制”">​</a></h3><p>不知道细心的朋友有没有发现，在疫情到来之前，我们大多接触到一些具有数字化特性的 C 端消费品（如：体脂秤具有称 + APP数据统计 + 虚拟社区；智能手表具有手表+数据收集与分析），只在办公时间或业余遇到紧急问题时才使用远程办公工具来协作，而疫情到来后我们更加主动拥抱、主动适应远程办公工具等数字化、虚拟化产品了。这在一定程度上也表明了：</p><ul><li>大家在紧锣密鼓地创造产品和服务的数字属性，并以文化、社群的方式加以体现，借助产品的数字化属性，甚至可以把需求方连成网络，从而基于虚拟网络提升服务市场的效率。</li><li>跨城市、跨地域地沟通协作已经成为了常态，<strong>地域化的问题在“数字化”趋势下能得到缓解，跨城市、跨地域地高效协作更容易被接受了</strong>。</li></ul><p>那么问题来了，一个普通的打工人去延伸思考这些东西有什么用处呢？这是不是类似刚入职的员工操着 CEO 的心，或者说一个普通百姓，业余闲着没事操着治理国家的心呢？笔者个人认为：都不是。而是想基于以上延伸思考引出一个新的业余尝试：<strong>业余跨地域协作</strong>。</p><p>这也关系到疫情后要不要继续实践混合工作制？不在其位就不谋其政，笔者这里不去谈国家或公司会不会在疫情后落地混合工作制，比如“3+2”或“4+1”工作制，因为笔者想延伸地是：<strong>如何在业余更大范围地尝试、实践混合工作制</strong>。</p><p>遥想当年学生时代，一群比较合得来的学生仅仅凭借几成勇气就在业余时间集中到一个物理空间内去捣鼓一些东西，也因为这样的折腾让我们顺利走向了工作岗位。走向工作岗位后，时不时会在虚拟社群中一起侃大山，聊聊工作与生活，吐槽一下自己的改变，但最终收尾的时候<strong>多少都还流露出想要搞些有点创造力或者正能量的事情。</strong></p><p>所以笔者认为，在上述延伸思考下，其实业余是可以协作的，主要原因有以下三点：</p><ul><li>基于远程工具协作已经被运用，人们已在疫情中适应了远程办公，跨城市、跨地域的阻碍因素在降低。</li><li>云服务已经发展得足够简单，很多基础设施已足够便捷（不再是当年在实验室或研究所里拿着裸机装软件的年代了）。</li><li>数字化是趋势，轻量、小而美、短期可完成的项目是可以协作完成的（虽然雇佣关系在一定时期内仍然是主导，但自由协作关系会越来越多）。</li></ul><p>其实最主要的<strong>问题还是在于有没有共同的诉求，能不能拿出时间来捣鼓，有没有人能组织且管理好这种自由的远程协作团伙，并合理分配项目收益，实现大家的共同诉求</strong>。在疫情中后期，笔者业余时间没少在由几个老伙计组成的社群中“传销”上述延伸思考，疫情结束后也可能会继续尝试下去。</p><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to “写在最后”">​</a></h2><p>行文至此，疫情这三年向内思变的复盘总结基本梳理完成了，不管文章最终的水平怎么样，依旧把自己的“闭关”经历沉淀下来了。</p><p>在文章的最后，顺便聊一聊思变。经历了疫情这三年，<strong>笔者认为思变不能只“打鸡血”或者 “立Flag”，思变是要结合客观事实和自身诉求来落地的</strong>。如果我们宽泛地谈改变，然后逼着自己变，挺内耗的。因为这种改变容易失败，失败后我们又不太容易原谅自己。可如果我们慢慢固化了，一旦大环境发生变化，我们又只能被动地任由社会教育。所以，改变之前需要多思考，需要学习一些知识套路尝试着实践。</p><p>笔者在落地上述几个话题的改变时，<strong>有些侧重实践为主，基于遇到的问题寻找解决方法；有些则以读书学习、与别人沟通交流的方式推动；还有些以业余娱乐的方式观察发现来推动</strong>，但最终实践的时候其实都初窥门径地用到了一些通识且有点哲学味道的“套路”：</p><ul><li><strong>分解与渐进明细</strong>，西方还原论的部分应用，“万物皆数”，对自然认知不断细化，尝试拆解分析出影响事物的本质原因。</li><li><strong>系统论</strong>，即围绕人和社会自身来改善多个影响因素，从而使自己更好地适应社会。</li><li><strong>知行合一</strong>，知是行的头脑，行是知的落实；知是行的开始，行是知的完成。</li></ul><p>最后，引用一下笔者早年看过的小说作为结束，其作者萧鼎老师说过“如果没有曾经的一段经历，自己写不出《诛仙》这样的作品”。虽然笔者与萧鼎老师相差甚远，也想在文章的最后说下：“如果没有疫情这三年的经历和刻意的向内思变，笔者也写不出一篇将多个话题串联起来的长文”。</p><p>之所以还记得《诛仙》这本小说，倒不是因为小说阐述了“天地不仁，以万物为刍狗”的法则，而是因为<strong>它也讲述了一个资质普通又平凡的少年，虽不醉心于修真，但真的凭借着坚韧、阅历一步步身兼“佛道魔”三种功法</strong>，这种特质在经济下行的大环境下可能更值得学习。</p>',121)])])}const u=r(o,[["render",s]]);export{d as __pageData,u as default};
